#include "bch_segmented/bch15_encoder.hpp"
#include "bch_segmented/bch15_lookup_decoder.hpp"
#include <fstream>
#include <stdexcept>
using namespace scl::bch::segmented;
int main(int argc,char**argv){try{if(argc!=2)throw std::runtime_error("output");auto t=buildBch15SyndromeTable();unsigned no=0,se=0,pos=0,post=0,miss=0,dtotal=0,dorig=0,dpayload=0,mis=0;for(unsigned v=0;v<2048;++v){scl::common::BitVector m(11);for(unsigned i=0;i<11;++i)m[i]=(v>>(10-i))&1;auto c=encodeBch15Systematic(m);auto z=decodeBch15Lookup(c,t);if(z.decodedMessage!=m)++no;for(unsigned p=0;p<15;++p){auto r=c;r[p]^=1;auto d=decodeBch15Lookup(r,t);if(d.decodedMessage!=m)++se;if(d.correctedPosition!=int(p))++pos;if(syndromeValue(d.syndromeAfter))++post;if(!d.lookupHit)++miss;}for(unsigned a=0;a<15;++a)for(unsigned b=a+1;b<15;++b){auto r=c;r[a]^=1;r[b]^=1;auto d=decodeBch15Lookup(r,t);++dtotal;if(d.correctedCodeword==c)++dorig;if(d.decodedMessage==m)++dpayload;if(d.status==Bch15DecodeStatus::CORRECTED_SINGLE_ERROR&&d.decodedMessage!=m)++mis;}}if(no||se||pos||post||miss||dtotal!=215040)throw std::runtime_error("audit");std::ofstream o(std::string(argv[1])+"/single_error_summary.csv");o<<"metric,value\nnoErrorPayloadMismatch,"<<no<<"\nsingleErrorPayloadMismatch,"<<se<<"\ncorrectedPositionMismatch,"<<pos<<"\npostSyndromeMismatch,"<<post<<"\nlookupMissForSingleError,"<<miss<<'\n';std::ofstream d(std::string(argv[1])+"/double_error_audit.csv");d<<"total,decodedToOriginalCodeword,decodedToOriginalPayload,miscorrectedToAnotherValidCodeword\n"<<dtotal<<','<<dorig<<','<<dpayload<<','<<mis<<'\n';return 0;}catch(const std::exception&e){return 1;}}
